import requests

def check_firmware_update():
    url = 'https://www.usa.canon.com/support'
    try:
        response = requests.get(url)
        response.raise_for_status()
        # Simplified logic: Assume the response contains info about firmware updates
        if 'EOS M6 Mark II' in response.text and '4K 24fps' in response.text:
            return "Firmware update for 24fps 4K recording is available."
        else:
            return "No firmware update information found or update not yet available."
    except requests.RequestException as e:
        return f"Error checking for updates: {e}"

print(check_firmware_update())
